private ConfigMetadata parseConsoleMetadata(String metaData) {
    if (StringUtils.isBlank(metaData)) {
        return null;
    }
    ConfigMetadata result = new ConfigMetadata();
    List<ConfigMetadata.ConfigExportItem> metadata = new ArrayList<>();
    String[] lines = CONSOLE_METADATA_LINE_SEPARATOR_PATTERN.split(metaData);
    for (String line : lines) {
        if (StringUtils.isBlank(line)) {
            continue;
        }
        String[] items = CONSOLE_METADATA_ITEM_SEPARATOR_PATTERN.split(line);
        int metadataItemLength = 3;
        if (items.length < metadataItemLength || StringUtils.isBlank(items[0]) || StringUtils.isBlank(items[1])) {
            return null;
        }
        ConfigMetadata.ConfigExportItem configExportItem = new ConfigMetadata.ConfigExportItem();
        configExportItem.setGroup(items[0]);
        configExportItem.setDataId(items[1]);
        configExportItem.setType(ConfigType.getDefaultType(configExportItem.getDataId()).getType());
        metadata.add(configExportItem);
    }
    result.setMetadata(metadata);
    return result;
}

